import{_ as a,o as t,c as r,ak as o,ao as i,am as l,an as n}from"./chunks/framework.C5oxOlRz.js";const u=JSON.parse('{"title":"快速开始","description":"","frontmatter":{"version":"2.1.8"},"headers":[],"relativePath":"guide/QUICK-START.md","filePath":"guide/QUICK-START.md","lastUpdated":1780022608000}'),s={name:"guide/QUICK-START.md"};function d(c,e,h,p,k,b){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h1><ul><li><a href="https://blog.csdn.net/qq_38765404/article/details/123497710/" target="_blank" rel="noreferrer">快速搭建 Jenkins 服务</a></li><li><a href="https://open.larksuite.com/document/client-docs/bot-v3/add-custom-bot" target="_blank" rel="noreferrer">Lark 自定义机器人指南</a></li><li><a href="https://open.feishu.cn/document/client-docs/bot-v3/add-custom-bot" target="_blank" rel="noreferrer">飞书自定义机器人指南</a></li><li><a href="https://open.dingtalk.com/document/orgapp/custom-robots-send-group-messages" target="_blank" rel="noreferrer">钉钉自定义机器人指南</a></li><li><a href="https://developer.work.weixin.qq.com/document/path/91770" target="_blank" rel="noreferrer">企业微信自定义机器人指南</a></li></ul><h2 id="环境准备" tabindex="-1">环境准备 <a class="header-anchor" href="#环境准备" aria-label="Permalink to “环境准备”">​</a></h2><p>开始之前，请确认运行环境满足以下要求：</p><table tabindex="0"><thead><tr><th>名称</th><th>版本</th></tr></thead><tbody><tr><td>Jenkins</td><td>2.541.3+</td></tr></tbody></table><h2 id="在线安装" tabindex="-1">在线安装 <a class="header-anchor" href="#在线安装" aria-label="Permalink to “在线安装”">​</a></h2><p>当前版本可能无法通过 Jenkins 更新中心直接获取。如果 <code>Jenkins</code> 更新中心地址（升级站点）不是 <a href="https://updates.jenkins.io/update-center.json" target="_blank" rel="noreferrer">官方镜像源</a>，通常无法检索到最新版本。</p><h2 id="离线安装" tabindex="-1">离线安装 <a class="header-anchor" href="#离线安装" aria-label="Permalink to “离线安装”">​</a></h2><p>建议优先通过发布页下载插件包：</p><ul><li><a href="https://github.com/721806280/lark-notice-plugin/releases" target="_blank" rel="noreferrer">GitHub Releases</a></li><li><a href="https://gitee.com/xm721806280/lark-notice-plugin/releases" target="_blank" rel="noreferrer">Gitee Releases</a></li></ul><p>在 Jenkins 中安装插件的步骤如下：</p><ol><li>打开 <code>系统管理</code> -&gt; <code>插件管理</code>。</li><li>进入 <code>Advanced</code> 或 <code>高级</code> 页面。</li><li>在 <code>Deploy Plugin</code> 区域上传下载好的插件包，或填写插件地址。</li><li>提交安装并按提示完成 Jenkins 重启。</li></ol><h2 id="机器人配置" tabindex="-1">机器人配置 <a class="header-anchor" href="#机器人配置" aria-label="Permalink to “机器人配置”">​</a></h2><h3 id="全局配置" tabindex="-1">全局配置 <a class="header-anchor" href="#全局配置" aria-label="Permalink to “全局配置”">​</a></h3><p>打开 <code>Manage Jenkins</code> 页面后，可通过 <code>Lark Notice</code> 管理入口进入，或在 <code>System Configuration</code> 页面中找到同名配置区块。</p><p><img src="'+i+'" alt=""></p><p>进入全局配置页面后，可新增机器人、配置安全策略、重试策略和通知时机等参数。</p><p><img src="'+l+'" alt=""></p><h3 id="添加机器人" tabindex="-1">添加机器人 <a class="header-anchor" href="#添加机器人" aria-label="Permalink to “添加机器人”">​</a></h3><p>添加机器人时，请先选择目标平台，再按提示填写 <code>Token / Key</code>，或切换到 <code>自定义</code> 模式填写完整 <code>Webhook</code>。</p><p><img src="'+n+`" alt=""></p><p>当前版本的机器人编辑器支持以下方式：</p><ul><li><code>Lark / 飞书</code>：默认输入机器人 <code>Token</code>，插件自动拼接官方 Webhook；如需私有域名或完整地址，请切换为 <code>自定义</code>。</li><li><code>钉钉</code>：默认输入 <code>access_token</code>，插件自动拼接官方 Webhook；如果已拿到完整 Webhook，也可以切换为 <code>自定义</code>。</li><li><code>企业微信</code>：默认输入群机器人 <code>key</code>，插件自动拼接官方 Webhook；如果需要完整地址，也可以切换为 <code>自定义</code>。</li></ul><p>保存后建议先点击机器人配置中的 <code>发送测试消息</code>，确认当前 Jenkins 网络、签名策略和代理设置均可正常访问目标平台。</p><blockquote><p>更多配置项（代理、重试策略、消息语言、安全策略、配置导入导出等）请参考 <a href="/lark-notice-plugin-doc/guide/feature/advanced.html">高级配置</a>。</p></blockquote><h3 id="jenkins-重启" tabindex="-1">Jenkins 重启 <a class="header-anchor" href="#jenkins-重启" aria-label="Permalink to “Jenkins 重启”">​</a></h3><p>插件安装或关键配置调整完成后，可通过以下地址执行 Jenkins 重启：</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 重启服务</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://[jenkins-server-address][:port]/restart</span></span></code></pre></div>`,28)])])}const m=a(s,[["render",d]]);export{u as __pageData,m as default};
